import BaseLayout from "../../layouts/BaseLayout.astro";
import {
  type Article,
  formatDisplayDate,
  getArticleContentBySlug,
  getArticles,
  getEntryPath,
} from "../../data/site";

export async function getStaticPaths() {
  const articles = await getArticles();
  return articles.map((article) => ({
    params: { slug: article.slug },
    props: { article },
  }));
}

const articles = await getArticles();

const { article } = Astro.props as { article: Article };
const articleContent = await getArticleContentBySlug(article.slug);

if (!articleContent) {
  throw new Error(`Article content not found for slug: ${article.slug}`);
}

const ArticleContent = articleContent.Content;

const articleIndex = articles.findIndex((candidate) => candidate.slug === article.slug);
const newer = articleIndex > 0 ? articles[articleIndex - 1] : undefined;
const older = articleIndex < articles.length - 1 ? articles[articleIndex + 1] : undefined;
---
<BaseLayout title={`${article.title} | The Mindful Engineer`} description={article.summary} path={getEntryPath(article)}>
  <div class="container">
    <header class="essay-header">
      <div class="essay-kicker">
        <span>Article</span>
        <span>/</span>
        <span>{formatDisplayDate(article.date)}</span>
        <span>/</span>
        <span>{article.readMinutes} minute read</span>
      </div>
      <h1 class="essay-title">{article.title}</h1>
      <p class="essay-sub">{article.deck}</p>
      <div class="essay-meta">
        <span>Benjamin Kitt</span>
        <span>Filed under: {article.tags.join(", ")}</span>
      </div>
    </header>

    <article class="essay-body">
      <ArticleContent />
      <div class="essay-end">o o o</div>
    </article>

    <footer class="essay-footer">
      <div class="essay-nav">
        {older ? (
          <a href={getEntryPath(older)}>
            <div class="dir">&lt;- Previous</div>
            <h4>{older.title}</h4>
          </a>
        ) : <div></div>}
      </div>
      <div class="essay-nav next">
        {newer ? (
          <a href={getEntryPath(newer)}>
            <div class="dir">Next -&gt;</div>
            <h4>{newer.title}</h4>
          </a>
        ) : <div></div>}
      </div>
    </footer>
  </div>
</BaseLayout>

