import { toText } from "hast-util-to-text";

const customNamespace = "https://mindful.engineer/ns";
const xmlBuilder = new XMLBuilder({
	ignoreAttributes: false,
	format: false,
	suppressEmptyNode: true,
});

export const htmlToPlainText = (value: string) => {
	const text = toText(fromHtml(value, { fragment: true }));
	return decodeHTML(text).replace(/\s+/g, " ").trim();
};

export const buildExternalUrlCustomData = (url: string) =>
	xmlBuilder.build({
		"mindful:externalUrl": {
			"@_xmlns:mindful": customNamespace,
			"#text": new URL(url).toString(),
		},
	});

export const truncateFeedText = (value: string, length = 80) => {
	if (value.length <= length) {
		return value;
	}

	return `${value.slice(0, length).replace(/\s+$/, "")}…`;
};

import rss from "@astrojs/rss";
import type { APIRoute } from "astro";
import {
	buildExternalUrlCustomData,
	htmlToPlainText,
	truncateFeedText,
} from "../data/feed";
import { getCanonicalUrl, getRecentStream, siteMeta } from "../data/site";

const getEntryDescription = (
	entry: Awaited<ReturnType<typeof getRecentStream>>[number],
) => {
	switch (entry.kind) {
		case "article":
			return entry.summary;
		case "note":
			return entry.body;
		case "link":
			return `${entry.body}\n\nExternal URL: ${entry.url}`;
		case "snippet":
			return `${entry.summary}\n\n${entry.code}`;
	}
};

const getEntryTitle = (
	entry: Awaited<ReturnType<typeof getRecentStream>>[number],
) => {
	switch (entry.kind) {
		case "article":
		case "link":
		case "snippet":
			return entry.title;
		case "note":
			return truncateFeedText(htmlToPlainText(entry.body), 80);
	}
};

export const GET: APIRoute = async (context) => {
	const stream = await getRecentStream();

	return rss({
		title: siteMeta.name,
		description: siteMeta.description,
		site: context.site ?? siteMeta.siteUrl,
		customData: `<language>en-us</language><managingEditor>${siteMeta.email} (${siteMeta.author})</managingEditor>`,
		items: stream.map((entry) => ({
			title: getEntryTitle(entry),
			pubDate: new Date(entry.date),
			description: getEntryDescription(entry),
			link: getCanonicalUrl(entry),
			customData:
				entry.kind === "link"
					? buildExternalUrlCustomData(entry.url)
					: undefined,
		})),
	});
};

import rss from "@astrojs/rss";
import type { APIRoute } from "astro";
import { htmlToPlainText, truncateFeedText } from "../../data/feed";
import {
	getCanonicalUrl,
	getLinks,
	getNotes,
	type Note,
	siteMeta,
} from "../../data/site";

type FeedEntry =
	| {
			kind: "note";
			date: string;
			title: string;
			description: string;
			link: string;
	  }
	| {
			kind: "link";
			date: string;
			title: string;
			description: string;
			link: string;
	  };

const noteTitle = (note: Note) =>
	truncateFeedText(htmlToPlainText(note.body), 80);

export const GET: APIRoute = async (context) => {
	const [notes, links] = await Promise.all([getNotes(), getLinks()]);

	const items: FeedEntry[] = [
		...notes.map(
			(note): FeedEntry => ({
				kind: "note",
				date: note.date,
				title: noteTitle(note),
				description: note.body,
				link: getCanonicalUrl(note),
			}),
		),
		...links.map(
			(link): FeedEntry => ({
				kind: "link",
				date: link.date,
				title: link.title,
				description: `${link.body}\n\nExternal URL: ${link.url}`,
				link: getCanonicalUrl(link),
			}),
		),
	].sort(
		(left, right) =>
			new Date(right.date).getTime() - new Date(left.date).getTime(),
	);

	return rss({
		title: `${siteMeta.name} / Notes + Links`,
		description: "Short-form notes and annotated links from mindful.engineer.",
		site: context.site ?? siteMeta.siteUrl,
		items: items.map((item) => ({
			title: item.title,
			description: item.description,
			pubDate: new Date(item.date),
			link: item.link,
		})),
	});
};

